function maxSumWindow(arr, k) {
  let maxSum = 0;
  let windowSum = 0;
  for (let i = 0; i < k; i++) {
    windowSum += arr[i];
  }
  maxSum = windowSum;
  for (let i = k; i < arr.length; i++) {
    windowSum += arr[i] - arr[i - k + 1];
    maxSum = Math.max(maxSum, windowSum);
  }
  return maxSum;
}
